// Compute position size, slippage, and Jupiter quote URL
const signal    = $('Get Signal').first().json;
const portfolio = $('Get Portfolio').first().json;

const sd          = signal.signal_data || {};
const tradeCard   = sd.trade_card || sd;

// Position size from Analyst trade card, capped at available USDC
let positionUsdt = parseFloat(tradeCard.position_size_usdt || sd.position_size_usdt || 50);
positionUsdt     = Math.min(positionUsdt, parseFloat(portfolio.available_usdc || 0));

if (positionUsdt < 5) {
  throw new Error('Insufficient USDC balance for trade (< $5)');
}

// Dynamic slippage based on position vs pool liquidity
const liquidityUsd = parseFloat(signal.liquidity_usd || 0);
let slippageBps;
if (!liquidityUsd || liquidityUsd <= 0) {
  slippageBps = 200;
} else {
  const impact = positionUsdt / liquidityUsd;
  if      (impact < 0.001) slippageBps = 30;
  else if (impact < 0.005) slippageBps = 50;
  else if (impact < 0.01)  slippageBps = 100;
  else if (impact < 0.02)  slippageBps = 200;
  else                     slippageBps = 300;
}

const USDC_MINT      = 'EPjFWdd5AufqSSqeM2qN1xzybapC8G4wEGGkZwyTDt1v';
const amountLamports = Math.floor(positionUsdt * Math.pow(10, 6));
const outputMint     = signal.token_address;

const quoteUrl = `https://quote-api.jup.ag/v6/quote?inputMint=${USDC_MINT}&outputMint=${outputMint}&amount=${amountLamports}&slippageBps=${slippageBps}&platformFeeBps=0`;

return [{
  json: {
    signal_id:     signal.id,
    symbol:        signal.symbol,
    direction:     signal.direction,
    token_address: signal.token_address,
    decimals:      signal.decimals || 6,
    liquidity_usd: liquidityUsd,
    position_usdt: positionUsdt,
    slippage_bps:  slippageBps,
    quote_url:     quoteUrl,
    entry_price:   parseFloat(tradeCard.entry_price || sd.entry_price || 0),
    stop_loss:     parseFloat(tradeCard.stop_loss   || sd.stop_loss   || 0),
    take_profit:   parseFloat(tradeCard.take_profit || sd.take_profit || 0)
  }
}];

// Validate Jupiter quote — check price impact, extract key fields
const quote    = $input.item.json;
const calcData = $('Calc Position & Slippage').item.json;

if (!quote?.outAmount) {
  throw new Error('Jupiter quote failed: no outAmount');
}

const priceImpact = parseFloat(quote.priceImpactPct || 0);
if (priceImpact > 3) {
  throw new Error(`Price impact too high: ${priceImpact.toFixed(2)}% (max 3%)`);
}

const decimals     = calcData.decimals;
const outputTokens = parseInt(quote.outAmount) / Math.pow(10, decimals);
const inputUsdc    = parseInt(quote.inAmount)  / Math.pow(10, 6);
const effectivePrice = outputTokens > 0 ? inputUsdc / outputTokens : 0;

return [{
  json: {
    ...calcData,
    quote_response:   quote,
    input_amount:     parseInt(quote.inAmount),
    output_amount:    parseInt(quote.outAmount),
    output_tokens:    outputTokens,
    effective_price:  effectivePrice,
    price_impact_pct: priceImpact,
    route_plan:       quote.routePlan?.map(r => r.swapInfo?.label).filter(Boolean) || []
  }
}];

// Get wallet public key from signer service health check
// Note: in production, use the public key returned by GET /health at startup
// For the swap tx, we need to replace SIGNER_PUBKEY_PLACEHOLDER with real key
const swapTxData  = $input.item.json;
const quoteData   = $('Validate Quote').item.json;

if (!swapTxData?.swapTransaction) {
  throw new Error('Jupiter swap build failed: no swapTransaction');
}

return [{
  json: {
    ...quoteData,
    swap_transaction: swapTxData.swapTransaction,
    last_valid_block_height: swapTxData.lastValidBlockHeight
  }
}];

// Merge signer response with trade data for DB save
const signerResp = $input.item.json;
const tradeData  = $('Prepare for Signing').item.json;

return [{
  json: {
    signal_id:        tradeData.signal_id,
    symbol:           tradeData.symbol,
    direction:        tradeData.direction,
    token_address:    tradeData.token_address,
    decimals:         tradeData.decimals,
    liquidity_usd:    tradeData.liquidity_usd,
    position_usdt:    tradeData.position_usdt,
    entry_price:      tradeData.effective_price,
    stop_loss:        tradeData.stop_loss,
    take_profit:      tradeData.take_profit,
    slippage_bps:     tradeData.slippage_bps,
    price_impact_pct: tradeData.price_impact_pct,
    output_tokens:    tradeData.output_tokens,
    route_plan:       tradeData.route_plan,
    tx_signature:     signerResp.signature,
    explorer_url:     signerResp.explorerUrl
  }
}];

// Send Telegram confirmation for successful DEX trade
const t  = $('Merge Result').first().json;
const ip = t.entry_price  < 0.001 ? t.entry_price.toFixed(8) : t.entry_price.toFixed(4);
const sl = t.stop_loss    < 0.001 ? t.stop_loss.toFixed(8)   : t.stop_loss.toFixed(4);
const tp = t.take_profit  < 0.001 ? t.take_profit.toFixed(8)  : t.take_profit.toFixed(4);

const lines = [
  `✅ *DEX Trade Executed: ${t.symbol}*`,
  `⚡ Solana/Jupiter`,
  ``,
  `Směr: *${t.direction?.toUpperCase()}*`,
  `Vstupní cena: \`${ip}\``,
  `SL: \`${sl}\`  |  TP: \`${tp}\``,
  `Pozice: *$${t.position_usdt.toFixed(2)}*`,
  `Slippage: ${t.slippage_bps}bps  |  Impact: ${t.price_impact_pct?.toFixed(3) || '?'}%`,
  `Route: ${(t.route_plan || []).join(' → ') || 'direct'}`,
  ``,
  `📝 [Zkontroluj na Solscan](${t.explorer_url})`,
  `TX: \`${t.tx_signature?.substring(0, 20)}...\``
];

return [{ json: { text: lines.join('\n'), parse_mode: 'Markdown' } }];

// TX failed on-chain — build error Telegram message
const signerResp = $input.item.json;
const tradeData  = $('Prepare for Signing').item.json;

const errMsg = signerResp.error || signerResp.txError || 'Unknown error';
const text = [
  `❌ *DEX Trade FAILED: ${tradeData.symbol}*`,
  ``,
  `Chyba: \`${errMsg}\``,
  `Signal ID: ${tradeData.signal_id}`,
  `TX: ${signerResp.signature ? `\`${signerResp.signature.substring(0, 20)}...\`` : 'N/A'}`
].join('\n');

return [{ json: { text, signal_id: tradeData.signal_id } }];
